(function(){const toggleBtn=document.getElementById("theme-toggle");const doc=document.documentElement;const getInitialTheme=()=>{const saved=localStorage.getItem("theme");if(saved)return saved;return window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light"};const applyTheme=(theme,save=false)=>{doc.setAttribute("data-theme",theme);toggleBtn.textContent=theme==="dark"?"light mode":"dark mode";if(save)localStorage.setItem("theme",theme)};const currentTheme=getInitialTheme();applyTheme(currentTheme);toggleBtn.addEventListener("click",()=>{const nextTheme=doc.getAttribute("data-theme")==="dark"?"light":"dark";applyTheme(nextTheme,true)});window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",e=>{if(!localStorage.getItem("theme")){applyTheme(e.matches?"dark":"light")}})})();